import{_ as s,o as t,c as a,a2 as n}from"./chunks/framework.DTa47_fH.js";const m=JSON.parse('{"title":"Hybrid Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"assessment/hybrid.md","filePath":"assessment/hybrid.md"}'),i={name:"assessment/hybrid.md"};function o(r,e,d,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="hybrid-assessment" tabindex="-1">Hybrid Assessment <a class="header-anchor" href="#hybrid-assessment" aria-label="Permalink to &quot;Hybrid Assessment&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Coming soon</p><p>Hybrid Assessment is on the roadmap. The description below reflects the planned capability.</p></div><p>Hybrid Assessment combines Application Assessment passes with Audit evidence to produce the highest-fidelity compliance picture available. It merges LLM-derived signals from source code analysis with consultant-authored findings from structured interviews and document review, delivering a unified publication that satisfies both technical and human-evidence requirements.</p><p><strong>Planned CLI:</strong> <code>swao assess --type hybrid</code></p><p><strong>TUI:</strong> Main Menu &gt; Run Assessment &gt; [5] Hybrid Assessment (coming soon)</p><hr><h2 id="when-to-use-hybrid-assessment" tabindex="-1">When to use Hybrid Assessment <a class="header-anchor" href="#when-to-use-hybrid-assessment" aria-label="Permalink to &quot;When to use Hybrid Assessment&quot;">​</a></h2><p>Use Hybrid Assessment when:</p><ul><li>The application has source code available <strong>and</strong> a consultant has conducted interviews or document review that adds evidence not visible from code alone.</li><li>A regulatory submission requires both automated analysis evidence and human-attestation sign-off on the same set of controls.</li><li>You want the highest possible rationale coverage rate (signals substantiated by both automated and human evidence carry stronger weight in an audit).</li></ul><hr><h2 id="how-it-will-work" tabindex="-1">How it will work <a class="header-anchor" href="#how-it-will-work" aria-label="Permalink to &quot;How it will work&quot;">​</a></h2><ol><li>Run an <strong>Application Assessment</strong> to produce the source-derived signal set.</li><li>Run an <strong>Audit Assessment</strong> to produce the consultant-authored evidence set.</li><li>Run <code>swao assess --type hybrid</code> to merge both signal sets. SWAO resolves any conflicts between automated and human verdicts using a configurable precedence rule (by default, human attestation overrides automated findings when both cover the same control).</li><li>Generate the combined publication and BI export.</li></ol><p>The merged output clearly attributes each signal to its source -- <code>source_code</code>, <code>context_doc</code>, or <code>consultant_attestation</code> -- so auditors can distinguish the evidence types.</p>',13)])])}const p=s(i,[["render",o]]);export{m as __pageData,p as default};
